def zip_strict(a, b):
    if len(a) != len(b):
        raise ValueError("desalineado")
    return list(zip(a, b))
try:
    zip_strict([1, 2, 3], [10, 20])
except ValueError:
    print("DESALINEADO")
try:
    print("OK", zip_strict([1, 2], [3, 4]))
except ValueError:
    print("DESALINEADO")

